mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM HM_MEMBER
    WHERE LOGIN_ID = #{loginId}
)

SELECT EXISTS (
    SELECT 1
    FROM HM_MEMBER
    WHERE NICKNAME = #{nickname}
)

SELECT EXISTS (
    SELECT 1
    FROM HM_MEMBER
    WHERE NICKNAME = #{nickname}
      AND MEMBER_ID <> #{memberId}
      AND MEMBER_STATUS <> 'WITHDRAWN'
)

mapper.update:
UPDATE HM_MEMBER
SET NICKNAME = #{nickname},
    EMAIL = #{email}
WHERE MEMBER_ID = #{memberId}
  AND MEMBER_STATUS = 'ACTIVE'

UPDATE HM_MEMBER
SET PASSWORD = #{encodedPassword}
WHERE MEMBER_ID = #{memberId}
  AND MEMBER_STATUS = 'ACTIVE'

UPDATE HM_MEMBER
SET PROFILE_IMAGE_URL = #{storedFileName}
WHERE MEMBER_ID = #{memberId}
  AND MEMBER_STATUS = 'ACTIVE'
